target.css:
:root {
  --card-bg: #ffffff;
  --card-border: #e2e8f0;
  --card-radius: 16px;
  --header-accent: #7c3aed;
  --badge-bg: #7c3aed;
  --badge-text: #ffffff;
  --lang-name-color: #1e1b4b;
  --lang-level-color: #6b7280;
  --flame-bg: #fff7ed;
  --flame-border: #fed7aa;
  --flame-count-color: #ea580c;
  --progress-track: #f1f5f9;
  --progress-fill: #7c3aed;
  --progress-label-color: #374151;
  --xp-value-color: #7c3aed;
  --skill-bg: #f8f7ff;
  --skill-border: #ede9fe;
  --skill-name-color: #4b5563;
  --skill-score-color: #7c3aed;
  --day-bg: #f1f5f9;
  --day-text: #9ca3af;
  --day-active-bg: #7c3aed;
  --day-active-text: #ffffff;
  --day-today-bg: #ddd6fe;
  --day-today-text: #5b21b6;
  --section-divider: #f1f5f9;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
  padding: 20px;
  box-sizing: border-box;
}

.streak-card {
  background: var(--card-bg);
  border: 1.5px solid var(--card-border);
  border-radius: var(--card-radius);
  padding: 20px;
  width: 420px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.card-header {
  display: flex;
  align-items: center;
  gap: 12px;
}

.lang-badge {
  background: var(--badge-bg);
  color: var(--badge-text);
  font-size: 15px;
  font-weight: 700;
  width: 44px;
  height: 44px;
  border-radius: 12px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.header-text {
  display: flex;
  flex-direction: column;
  gap: 2px;
  flex: 1;
}

.lang-name {
  font-size: 17px;
  font-weight: 700;
  color: var(--lang-name-color);
  line-height: 1.2;
}

.lang-level {
  font-size: 12px;
  font-weight: 500;
  color: var(--lang-level-color);
}

.streak-flame {
  display: flex;
  flex-direction: column;
  align-items: center;
  background: var(--flame-bg);
  border: 1.5px solid var(--flame-border);
  border-radius: 10px;
  padding: 6px 12px;
  gap: 1px;
}

.flame-icon {
  font-size: 18px;
  line-height: 1;
}

.flame-count {
  font-size: 13px;
  font-weight: 700;
  color: var(--flame-count-color);
  line-height: 1;
}

.progress-section {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.progress-label {
  display: flex;
  justify-content: space-between;
  font-size: 12px;
  font-weight: 500;
  color: var(--progress-label-color);
}

.xp-value {
  color: var(--xp-value-color);
  font-weight: 600;
}

.progress-bar {
  background: var(--progress-track);
  border-radius: 99px;
  height: 10px;
  overflow: hidden;
}

.progress-fill {
  background: var(--progress-fill);
  height: 100%;
  width: 68%;
  border-radius: 99px;
}

.skills-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px;
}

.skill-item {
  background: var(--skill-bg);
  border: 1.5px solid var(--skill-border);
  border-radius: 10px;
  padding: 10px 6px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.skill-icon {
  font-size: 18px;
  line-height: 1;
}

.skill-name {
  font-size: 11px;
  font-weight: 500;
  color: var(--skill-name-color);
}

.skill-score {
  font-size: 13px;
  font-weight: 700;
  color: var(--skill-score-color);
}

.week-row {
  display: flex;
  justify-content: space-between;
  gap: 6px;
  border-top: 1.5px solid var(--section-divider);
  padding-top: 14px;
}

.day-dot {
  flex: 1;
  height: 34px;
  border-radius: 8px;
  background: var(--day-bg);
  color: var(--day-text);
  font-size: 11px;
  font-weight: 600;
  display: flex;
  align-items: center;
  justify-content: center;
}

.day-dot.active {
  background: var(--day-active-bg);
  color: var(--day-active-text);
}

.day-dot.today {
  background: var(--day-today-bg);
  color: var(--day-today-text);
}

